1	export type Item = {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	};
7	
8	export type QuoteStep = {
9	  op: "quote";
10	  items: Item[];
11	};
12	
13	export type Step = QuoteStep;
14	
15	export type Scenario = {
16	  customer: { yearsWithMHPCO: number };
17	  steps: Step[];
18	};
19	
20	export type QuoteResult = { premium: number };
21	export type StepResult = QuoteResult;
22	
23	export type ScenarioResult = {
24	  results: StepResult[];
25	};
26	
27	const PROCESSING_FEE = 5;
28	const FIRST_CONTRACT_SURCHARGE_RATE = 0.1;
29	const BLOCK_OF_THREE_DISCOUNT = 15;
30	const CURSE_SURCHARGE_RATE = 0.5;
31	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
32	const HIGH_ENCHANTMENT_THRESHOLD = 5;
33	const LOYALTY_DISCOUNT_RATE = 0.2;
34	const LOYALTY_YEARS_THRESHOLD = 2;
35	
36	const BASE_PREMIUM: Record<string, number> = {
37	  sword: 100,
38	  amulet: 60,
39	  staff: 80,
40	  potion: 40,
41	  rune: 25,
42	  moonstone: 25,
43	};
44	
45	const COMPONENT_TYPES = ["rune", "moonstone"];
46	
47	const blockOfThreeDiscount = (alikeComponentCount: number): number =>
48	  alikeComponentCount === 3 ? BLOCK_OF_THREE_DISCOUNT : 0;
49	
50	const countItemsOfType = (items: Item[], type: string): number =>
51	  items.filter((item) => item.type === type).length;
52	
53	const isCursed = (item: Item): boolean => item.cursed === true;
54	const isHighlyEnchanted = (item: Item): boolean =>
55	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
56	
57	const ITEM_SURCHARGE_RATES: ReadonlyArray<{
58	  applies: (item: Item) => boolean;
59	  rate: number;
60	}> = [
61	  { applies: isCursed, rate: CURSE_SURCHARGE_RATE },
62	  { applies: isHighlyEnchanted, rate: HIGH_ENCHANTMENT_SURCHARGE_RATE },
63	];
64	
65	const basePremiumFor = (item: Item): number => {
66	  if (!(item.type in BASE_PREMIUM)) {
67	    throw new Error(`Unknown item type: ${item.type}`);
68	  }
69	  return BASE_PREMIUM[item.type];
70	};
71	
72	const surchargesForItem = (item: Item): number => {
73	  const base = basePremiumFor(item);
74	  return ITEM_SURCHARGE_RATES.reduce(
75	    (sum, { applies, rate }) => sum + (applies(item) ? base * rate : 0),
76	    0,
77	  );
78	};
79	
80	const sumItemSpecificSurcharges = (items: Item[]): number =>
81	  items.reduce((sum, item) => sum + surchargesForItem(item), 0);
82	
83	const calculateBasePremium = (items: Item[]): number => {
84	  const subtotal = items.reduce((sum, item) => sum + basePremiumFor(item), 0);
85	  const totalDiscount = COMPONENT_TYPES.reduce(
86	    (sum, type) => sum + blockOfThreeDiscount(countItemsOfType(items, type)),
87	    0,
88	  );
89	  return subtotal - totalDiscount;
90	};
91	
92	const firstContractSurcharge = (basePremium: number): number =>
93	  basePremium * FIRST_CONTRACT_SURCHARGE_RATE;
94	
95	const qualifiesForLoyaltyDiscount = (yearsWithMHPCO: number): boolean =>
96	  yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
97	
98	const loyaltyDiscount = (basePremium: number, yearsWithMHPCO: number): number =>
99	  qualifiesForLoyaltyDiscount(yearsWithMHPCO) ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
100	
101	const quote = (step: QuoteStep, customer: Scenario["customer"]): QuoteResult => {
102	  const basePremium = calculateBasePremium(step.items);
103	  const itemSurcharges = sumItemSpecificSurcharges(step.items);
104	  const premium = Math.ceil(
105	    basePremium +
106	      itemSurcharges +
107	      firstContractSurcharge(basePremium) -
108	      loyaltyDiscount(basePremium, customer.yearsWithMHPCO) +
109	      PROCESSING_FEE,
110	  );
111	  return { premium };
112	};
113	
114	export const runScenario = (scenario: Scenario): ScenarioResult => {
115	  const results = scenario.steps.map((step) => quote(step, scenario.customer));
116	  return { results };
117	};
